INSERT INTO `edu_news` VALUES
('100', '我校举办2026年春季学期教学创新大赛', '4月18日，我校2026年春季学期教学创新大赛决赛在科学校区学术报告厅隆重举行，来自18个学院的36位教师同台竞技。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>4月18日，郑州轻工业大学2026年春季学期教学创新大赛决赛在科学校区学术报告厅隆重举行。本次大赛以"融合创新、提质赋能"为主题，经过各学院初赛选拔，共有来自18个教学单位的36位教师进入校级决赛。</p><p>大赛分为教学设计汇报和现场授课展示两个环节。参赛教师围绕混合式教学、课程思政融入、项目驱动教学、虚拟仿真应用等前沿主题进行了精彩展示，充分展现了新时代高校教师的教学创新能力和专业素养。评审专家组由校内外7位教学名师组成，从教学设计、课堂实施、教学效果三个维度进行综合评价。</p><p>经过一天激烈角逐，最终评选出一等奖3项、二等奖6项、三等奖9项。校长出席颁奖仪式并为获奖教师颁发荣誉证书，鼓励全校教师以赛促教、以赛促改，持续提升课堂教学质量和育人水平。</p>', '2026-04-19 16:00:00', '458', '1', '92', '0', '2', 'admin', '2026-04-19 16:00:00', '', '2026-04-19 16:00:00', '0'),

('101', '软件学院教师在省级教学竞赛中荣获一等奖', '在2026年河南省本科高校教师课堂教学创新大赛中，我校软件学院教师凭借出色的教学设计和课堂表现荣获理工组一等奖。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>近日，由河南省教育厅主办的2026年河南省本科高校教师课堂教学创新大赛圆满落幕。我校软件学院张伟老师凭借"面向对象程序设计"课程的教学展示，荣获理工组一等奖；外国语学院孙悦老师获文科组二等奖。</p><p>本次大赛共有来自全省56所本科高校的180余名教师参赛。张伟老师在比赛中展示了其独创的"案例驱动+项目实战+翻转课堂"三位一体教学模式，将企业真实项目引入课堂，引导学生在解决实际问题中掌握编程技能。教学过程中融入课程思政元素，培养学生的职业素养和社会责任感。</p><p>教务处负责人表示，学校高度重视教师教学能力建设，近年来通过组织教学创新大赛、开展教学能力培训、设立教学改革专项等多种方式，有效提升了教师队伍的整体教学水平。此次获奖是对我校教师教学创新工作的充分肯定。</p>', '2026-04-05 10:30:00', '386', '1', '88', '0', '2', 'admin', '2026-04-05 10:30:00', '', '2026-04-05 10:30:00', '0'),

('102', '计算机学院获批3项省级教学改革重点项目', '河南省教育厅公布2026年度省级教学改革研究项目立项名单，我校计算机与通信工程学院3个项目获批重点项目资助。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>近日，河南省教育厅正式公布了2026年度省级教学改革研究项目立项名单。我校计算机与通信工程学院共有3个项目获批为重点项目，每项资助经费20万元，资助总额达60万元，立项数量和资助金额均位居全省高校前列。</p><p>获批的三项重点项目分别为：赵强教授主持的"新工科背景下计算机类专业课程思政一体化建设研究"、刘洋副教授主持的"基于大语言模型的编程课程智能化教学改革"、陈静博士主持的"大数据驱动的计算机类课程过程性评价体系构建"。三项课题紧扣当前高等教育教学改革的热点难点问题，研究成果将有力推动我校计算机类专业建设和人才培养质量提升。</p><p>近年来，计算机与通信工程学院高度重视教学研究工作，积极组织教师申报各级各类教改项目，累计获批国家级教改项目2项、省级教改项目12项。学院负责人表示，将以项目研究为抓手，持续深化教育教学改革。</p>', '2026-04-12 09:00:00', '356', '1', '85', '0', '2', 'admin', '2026-04-12 09:00:00', '', '2026-04-12 09:00:00', '0'),

('103', '我校与华为共建人工智能联合实验室', '4月10日，郑州轻工业大学与华为技术有限公司签署合作协议，双方将共建人工智能联合实验室，推动AI领域产教融合。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>4月10日，郑州轻工业大学与华为技术有限公司在深圳华为总部签署了"人工智能联合实验室"共建协议。校长与华为河南公司总经理代表双方签约。</p><p>根据协议，联合实验室将聚焦计算机视觉、自然语言处理、工业智能三个研究方向，华为将提供昇腾AI计算平台、ModelArts开发平台等软硬件资源，学校提供场地、师资和科研团队。实验室规划建筑面积800平方米，包括AI算力中心、创新工坊和成果展示中心三大功能区，预计今年9月正式投入使用。双方还将在课程共建、师资培训、学生实习、科研攻关等方面展开全面合作。</p><p>校长在签约仪式上表示，与华为共建联合实验室是学校深化产教融合的重要举措，将有力推动我校人工智能学科建设和应用型人才培养，为河南省数字经济发展提供人才支撑和智力支持。</p>', '2026-04-11 14:00:00', '489', '1', '95', '0', '2', 'admin', '2026-04-11 14:00:00', '', '2026-04-11 14:00:00', '0'),

('104', '外国语学院开展"AI+外语"教学研讨会', '4月16日，外国语学院举办"AI赋能外语教学"专题研讨会，探讨人工智能技术在语言教学中的创新应用路径。', '', '<p>4月16日下午，外国语学院在东风校区语言实验中心举办了"AI赋能外语教学"专题研讨会。来自省内外8所高校的60余名外语教师和教学管理人员参加了本次研讨活动。</p><p>研讨会邀请北京外国语大学梁茂成教授作题为"人工智能时代的外语教育变革"的主旨报告，深入分析了AI技术对外语教学理念、教学模式和评价方式带来的深刻影响。我校外国语学院马超教授分享了"基于AI技术的外语写作智能反馈系统"的研发经验，展示了系统在学生作文自动批改、语法纠错和学习路径推荐等方面的实际应用效果。</p><p>与会教师围绕"大语言模型辅助外语写作教学"、"AI口语陪练系统的课堂应用"、"个性化外语学习路径智能推荐"等话题进行了热烈讨论。外国语学院院长表示，学院将以此次研讨会为契机，加快推动AI技术与外语教学的深度融合，探索"AI+外语"教学改革新模式。</p>', '2026-04-17 15:00:00', '238', '1', '72', '0', '2', 'admin', '2026-04-17 15:00:00', '', '2026-04-17 15:00:00', '0'),

('105', '数学学院在全国大学生数学建模竞赛中再创佳绩', '2025年"高教社杯"全国大学生数学建模竞赛成绩揭晓，我校代表队获国家级一等奖3项、二等奖6项，创历史新高。', '', '<p>日前，2025年"高教社杯"全国大学生数学建模竞赛获奖名单正式公布。我校选派的30支参赛队伍中，共有24支队伍获奖，获奖率高达80%。其中，国家级一等奖3项、二等奖6项，省级一等奖8项、二等奖7项，获奖数量和质量均创我校参赛历史最佳成绩。</p><p>全国大学生数学建模竞赛是由中国工业与应用数学学会主办的面向全国大学生的群众性科技活动，是首批列入"高校学科竞赛排行榜"的19项竞赛之一。2025年全国共有来自1600余所院校的5万余支队伍、超过15万名学生报名参赛，竞争异常激烈。</p><p>数学与信息科学学院负责人表示，优异成绩的取得离不开指导教师的辛勤付出和学生的刻苦钻研。学院长期坚持"以赛促学、以赛促教"的人才培养理念，建立了完善的赛前培训体系和跨学科指导团队，为竞赛成绩的持续提升奠定了坚实基础。</p>', '2026-03-18 10:00:00', '475', '1', '82', '0', '2', 'admin', '2026-03-18 10:00:00', '', '2026-03-18 10:00:00', '0'),

('106', '电气学院虚拟仿真实验教学平台投入使用', '电气信息工程学院建设的电力系统虚拟仿真实验教学平台正式投入使用，覆盖发电、输电、变电、配电全流程实验。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>4月8日，电气信息工程学院电力系统虚拟仿真实验教学平台通过验收并正式投入使用。该平台由学院教师团队历时一年半自主研发，累计投入建设经费120万元。</p><p>平台基于MATLAB/Simulink和ETAP两大仿真软件构建，涵盖发电厂仿真、输电网潮流分析、变电站继电保护、配电网自动化、新能源并网控制等12个实验模块，可支持《电力系统分析》、《继电保护》、《高电压技术》、《新能源发电技术》等核心课程的实验教学需求。平台采用B/S架构，学生通过浏览器即可远程完成实验操作，打破了传统电力实验受限于硬件设备和安全条件的瓶颈。</p><p>平台试运行三个月期间，已有4个专业、12个教学班的400余名学生使用，实验开出率从原来的65%提升至100%。学生普遍反映虚拟仿真平台操作直观、反馈及时，对理解抽象电力概念有显著帮助。</p>', '2026-04-09 11:00:00', '312', '1', '78', '0', '2', 'admin', '2026-04-09 11:00:00', '', '2026-04-09 11:00:00', '0'),

('107', '经管学院举办数字经济时代管理教育论坛', '4月8日，经济与管理学院举办"数字经济时代的管理教育"学术论坛，探讨数字化转型背景下管理学科教育改革新路径。', '', '<p>4月8日，经济与管理学院在科学校区学术交流中心举办了"数字经济时代的管理教育"主题论坛。论坛邀请了中国人民大学、西安交通大学、中南财经政法大学等高校的5位知名管理学者作学术报告，来自校内外的120余名师生参加了论坛。</p><p>论坛围绕"数字经济对管理教育的挑战与机遇"、"大数据与AI在管理课程中的整合应用"、"新商科人才培养模式转型"、"产教融合驱动管理教育改革"四个议题进行了深入研讨。与会专家一致认为，数字经济时代的管理教育必须加快数字化转型步伐，着力培养学生的数据思维、平台思维和创新思维，推动管理类课程内容从传统理论向数字实践转变。</p><p>经济与管理学院院长在论坛总结中表示，学院将以此次论坛成果为指引，加快推进管理类课程的数字化转型，优化人才培养方案，努力培养适应数字经济发展需求的高素质管理人才。</p>', '2026-04-10 09:00:00', '185', '1', '65', '0', '2', 'admin', '2026-04-10 09:00:00', '', '2026-04-10 09:00:00', '0'),

('108', '学校召开2026年本科教学工作推进会', '3月25日，学校召开2026年本科教学工作推进会，部署年度教学重点任务，强调以审核评估为契机全面提升育人质量。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>3月25日上午，郑州轻工业大学2026年本科教学工作推进会在科学校区办公楼第一会议室召开。校长出席会议并讲话，各学院院长、教学副院长、教务处全体工作人员参加会议。</p><p>会议全面部署了2026年本科教学八项重点工作：一是高质量推进一流专业和一流课程建设，力争新增2-3个国家级一流专业建设点；二是深化课程思政教学改革，实现所有专业课程思政全覆盖；三是加强实践教学体系建设，提升实验室利用率和开放共享水平；四是全力做好本科教育教学审核评估迎评工作；五是推进教师教学能力提升工程，打造高素质教师队伍；六是完善教学质量保障体系，建立常态化监测机制；七是深化产教融合协同育人，拓展校企合作深度和广度；八是加快教育数字化转型，推动信息技术与教学深度融合。</p><p>校长强调，2026年是学校建设高水平轻工业大学的关键之年，各学院要以审核评估为契机，坚持"以评促建、以评促改、以评促管、以评促强"方针，全面提升本科教育教学质量。</p>', '2026-03-26 08:30:00', '523', '1', '90', '0', '2', 'admin', '2026-03-26 08:30:00', '', '2026-03-26 08:30:00', '0'),

('109', '我校获批教育部产教融合协同育人项目12项', '教育部高等教育司公布2025年第二批产学合作协同育人项目立项名单，我校获批12项，立项数量连续三年位居全省前列。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>近日，教育部高等教育司公布了2025年度第二批产学合作协同育人项目立项名单。我校共有12个项目成功获批立项，立项数量连续三年位居河南省属高校前列。</p><p>本次获批项目涵盖新工科建设、教学内容和课程体系改革、师资培训、实践条件和实践基地建设四个领域。合作企业包括华为、腾讯云、科大讯飞、中软国际、新道科技等知名企业，项目内容涉及人工智能课程资源开发、大数据实训平台建设、工业互联网实践基地共建、智能财务人才培养等多个方向。</p><p>教务处负责人表示，教育部产学合作协同育人项目是深化产教融合、校企合作的重要载体。学校将持续加强项目管理，确保项目高质量实施，通过校企协同培养更多适应产业发展需求的高素质应用型人才。</p>', '2026-03-22 14:00:00', '367', '1', '84', '0', '2', 'admin', '2026-03-22 14:00:00', '', '2026-03-22 14:00:00', '0'),

('110', '教务处新版教学成果管理平台上线运行', '经过三个月的开发测试，新版教学成果管理平台正式上线，实现成果申报、审核、统计全流程在线管理。', '', '<p>经过近三个月的紧张开发和测试，新版教学成果管理平台已于近日正式上线运行。该平台基于Spring Cloud微服务架构开发，全面实现了教学成果从申报、审核、公示到统计分析的全流程在线管理。</p><p>新版平台具有以下亮点功能：一是支持富文本编辑器，教师可在线撰写成果详细内容，支持图文混排和多种格式附件上传；二是支持多级审核流程，涵盖院级初审和校级终审两个环节，审核过程全程留痕；三是提供丰富的统计分析和数据可视化功能，可按学院、类型、等级、年份等维度自动生成统计报表和趋势图表；四是优化了门户展示功能，审核通过的成果可自动推送到门户网站公开展示，支持按浏览量和发布时间排序。</p><p>平台上线两周以来，已有超过80位教师使用平台提交了教学成果申报，系统运行稳定。教务处将根据用户反馈持续优化平台功能，提升使用体验。</p>', '2026-03-12 10:00:00', '298', '1', '76', '0', '2', 'admin', '2026-03-12 10:00:00', '', '2026-03-12 10:00:00', '0'),

('111', '我校教师在第三届全国高校教师教学创新大赛中获佳绩', '我校3位教师在第三届全国高校教师教学创新大赛中斩获佳绩，分别获得二等奖1项、三等奖2项。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>近日，由教育部高等教育司指导、中国高等教育学会主办的第三届全国高校教师教学创新大赛全国总决赛圆满落幕。经过激烈角逐，我校共有3位教师获奖，其中电气信息工程学院郑丽教授荣获副高组二等奖，软件学院张伟老师获中级及以下组三等奖，外国语学院孙悦老师获中级及以下组三等奖。</p><p>全国高校教师教学创新大赛是教育部直属单位主办的规模最大、影响力最广的全国性教师教学赛事，本届大赛以"推进教学创新、培养一流人才"为主题，全国32个赛区的上千所高校的教师参赛，最终仅有不到200名教师进入全国总决赛。</p><p>我校参赛教师在大赛中充分展现了先进的教学理念、扎实的专业功底和突出的创新能力。学校教师发展中心表示，将以此为契机，进一步构建完善教师教学能力发展体系，推动全校教师教学水平持续提升。</p>', '2026-03-08 09:00:00', '416', '1', '87', '0', '2', 'admin', '2026-03-08 09:00:00', '', '2026-03-08 09:00:00', '0'),

('112', '外国语学院学生在全国大学生英语竞赛中获特等奖', '2026年全国大学生英语竞赛（NECCS）成绩公布，我校外国语学院学生表现突出，斩获特等奖1项、一等奖3项。', '', '<p>近日，2026年全国大学生英语竞赛（NECCS）全国总决赛成绩正式公布。我校外国语学院学生表现优异，英语专业组获特等奖1项、一等奖3项、二等奖5项；大学英语组获一等奖2项、二等奖8项、三等奖12项，获奖数量和等级均创我校参赛最好成绩。</p><p>全国大学生英语竞赛是经教育部批准、由高等学校大学外语教学指导委员会和高等学校大学外语教学研究会联合主办的全国性大学生英语综合能力竞赛，每年举办一届，是全国规模最大的英语学科竞赛之一。本届大赛全国共有1300余所高校的120余万名学生参赛。</p><p>外国语学院历来重视学科竞赛工作，将竞赛指导与日常教学有机融合，建立了"课内拓展+课外训练+赛前集训"三位一体的竞赛指导模式。近三年累计获得国家级奖项15项、省级奖项60余项，竞赛育人成效显著。</p>', '2026-04-15 11:00:00', '402', '1', '74', '0', '2', 'admin', '2026-04-15 11:00:00', '', '2026-04-15 11:00:00', '0'),

('113', '软件学院入选国家级一流本科专业建设点', '教育部公布2025年度国家级一流本科专业建设点名单，我校软件工程专业成功入选，专业建设迈上新台阶。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>近日，教育部办公厅正式公布了2025年度国家级一流本科专业建设点名单，我校软件工程专业成功入选。这是继食品科学与工程、高分子材料与工程、计算机科学与技术之后，我校获批的第四个国家级一流本科专业建设点。</p><p>软件工程专业始建于2004年，经过二十余年的建设发展，已经形成了"厚基础、宽口径、强实践、重创新"的人才培养特色。该专业近年来在课程建设、教材建设、实验平台建设等方面取得了显著成绩，建有省级精品在线开放课程3门、省级虚拟仿真实验教学项目2个。学生在全国大学生服务外包创新创业大赛、中国大学生计算机设计大赛等高水平赛事中屡获佳绩，近三年累计获国家级奖项8项、省级奖项25项。</p><p>软件学院负责人表示，将以国家级一流专业建设为契机，进一步深化产教融合，优化人才培养方案，努力打造国内有影响力的软件工程人才培养高地。</p>', '2026-03-02 09:00:00', '505', '1', '93', '0', '2', 'admin', '2026-03-02 09:00:00', '', '2026-03-02 09:00:00', '0'),

('114', '我校承办2026年河南省高校教务处长工作会议', '4月1日，2026年河南省高校教务处长工作会议在我校召开，全省57所本科高校教务处长参加会议。', '', '<p>4月1日，2026年河南省高校教务处长工作会议在郑州轻工业大学科学校区顺利召开。省教育厅高教处处长出席会议并讲话，来自全省57所本科高校的教务处处长及教学管理骨干共120余人参加会议。</p><p>会议总结了2025年全省本科教育教学工作取得的成绩，分析了当前面临的形势和挑战，部署了2026年重点工作任务。会上，郑州大学、河南大学、郑州轻工业大学等6所高校代表分别就一流专业建设、课程思政改革、创新创业教育、审核评估迎评等主题作了经验交流发言。</p><p>省教育厅高教处处长在讲话中强调，各高校要紧密对接国家战略和区域发展需求，深化教育教学改革，加强内涵建设，全面提升本科人才培养质量。要重点做好新一轮审核评估迎评工作，以评促建推动学校教育教学水平整体提升。会议期间，与会代表还参观了我校教学成果展和智慧教室建设成果。</p>', '2026-04-02 10:00:00', '274', '1', '80', '0', '2', 'admin', '2026-04-02 10:00:00', '', '2026-04-02 10:00:00', '0'),

('115', '电气学院学生在智能车竞赛中获全国一等奖', '在2026年全国大学生智能汽车竞赛中，我校电气信息工程学院代表队获全国一等奖1项、二等奖2项。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>近日，2026年全国大学生智能汽车竞赛全国总决赛圆满落幕。经过两天的激烈角逐，我校电气信息工程学院派出的3支代表队表现优异，获全国一等奖1项、二等奖2项，取得了我校在该赛事中的历史最佳成绩。</p><p>全国大学生智能汽车竞赛是教育部高等学校自动化类专业教学指导委员会主办的A类学科竞赛，以"立足培养、重在参与、鼓励探索、追求卓越"为指导思想，涵盖自动控制、模式识别、传感技术、电子电气、计算机、机械等多个学科领域。本届大赛全国共有500余所高校的3000余支队伍参赛。</p><p>获奖团队的指导教师周鹏老师介绍，自去年10月启动备赛以来，参赛学生利用课余时间和节假日，在实验室反复调试硬件电路、优化控制算法，付出了大量心血。此次获奖充分体现了我校电气信息类专业在实践教学和创新能力培养方面的突出成效。</p>', '2026-04-14 16:00:00', '345', '1', '77', '0', '2', 'admin', '2026-04-14 16:00:00', '', '2026-04-14 16:00:00', '0'),

('116', '我校新增3个省级课程思政样板课程', '河南省教育厅公布2026年度省级课程思政样板课程和教学团队名单，我校3门课程成功入选省级课程思政样板课程。', '', '<p>近日，河南省教育厅公布了2026年度省级课程思政样板课程和课程思政教学团队名单。我校《面向对象程序设计》、《电力系统分析》、《综合英语》3门课程成功入选省级课程思政样板课程，《经济学原理》课程教学团队入选省级课程思政教学团队。</p><p>近年来，学校深入贯彻落实教育部《高等学校课程思政建设指导纲要》，制定了《郑州轻工业大学课程思政建设实施方案》，将课程思政建设纳入人才培养方案修订、课程教学大纲制定和课堂教学评估全过程。各学院积极挖掘专业课程中的思政元素，打造了一批课程思政示范课堂和典型案例。</p><p>截至目前，我校已累计获批省级课程思政样板课程8门、省级课程思政教学团队3个。教务处表示，学校将继续深化课程思政教学改革，完善课程思政评价体系，推动课程思政建设走深走实。</p>', '2026-03-30 09:00:00', '287', '1', '73', '0', '2', 'admin', '2026-03-30 09:00:00', '', '2026-03-30 09:00:00', '0'),

('117', '学校组织开展2026年春季学期教学检查工作', '4月初，学校组织开展2026年春季学期期中教学检查，覆盖课堂教学、实践教学和教学档案管理三大方面。', '', '<p>为全面了解本学期教学工作运行状况，及时发现和解决教学过程中存在的问题，学校于4月7日至18日组织开展了2026年春季学期期中教学检查工作。检查由教务处牵头，校级教学督导组和各学院共同参与。</p><p>本次检查采取学院自查与学校抽查相结合的方式进行。检查内容主要包括三个方面：一是课堂教学质量，包括教师到岗情况、授课水平、学生到课率和课堂纪律等；二是实践教学环节，包括实验课程开出率、实习实训开展情况和毕业设计进展等；三是教学档案管理，包括教学日历执行、教案编写、作业批改和考试管理规范性等。</p><p>检查结果显示，本学期教学工作整体运行良好，教学秩序规范有序，课堂教学质量稳步提升。同时也发现部分新开课程的教学资源建设有待加强，个别实践教学环节的安全管理需进一步规范。教务处已对发现的问题逐项梳理，向相关学院下发了整改通知。</p>', '2026-04-20 08:00:00', '332', '1', '68', '0', '2', 'admin', '2026-04-20 08:00:00', '', '2026-04-20 08:00:00', '0'),

('118', '我校与科大讯飞签署产教融合战略合作协议', '4月22日，郑州轻工业大学与科大讯飞股份有限公司签署产教融合战略合作协议，共建AI产业学院。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>4月22日，郑州轻工业大学与科大讯飞股份有限公司产教融合战略合作签约仪式在科学校区举行。校长与科大讯飞高教事业部总经理代表双方签署协议。</p><p>根据协议，双方将在以下领域开展深度合作：一是共建"AI产业学院"，联合培养人工智能、大数据等方向的应用型人才；二是共建AI实训基地，科大讯飞提供语音识别、自然语言处理、计算机视觉等核心技术平台；三是联合开发AI系列课程和教材，推动AI技术融入多个学科专业；四是开展双师型教师培养，企业工程师定期进校授课，学校教师到企业实践锻炼；五是共建科研平台，围绕工业AI应用场景开展联合技术攻关。</p><p>校长表示，与科大讯飞合作是学校深化产教融合、推动AI赋能教育教学的重要举措。学校将以此次合作为契机，加快AI领域人才培养和科技创新步伐，为服务地方数字经济发展贡献力量。</p>', '2026-04-23 10:00:00', '213', '1', '94', '0', '2', 'admin', '2026-04-23 10:00:00', '', '2026-04-23 10:00:00', '0'),

('119', '经管学院学生在全国管理决策模拟大赛中获奖', '我校经济与管理学院学生在2026年"创新创业"全国管理决策模拟大赛中荣获国家级一等奖1项、二等奖2项。', '', '<p>近日，2026年"创新创业"全国管理决策模拟大赛全国总决赛成绩公布。我校经济与管理学院选派的4支代表队表现优异，获国家级一等奖1项、二等奖2项、三等奖1项。</p><p>全国管理决策模拟大赛由教育部高等学校工商管理类专业教学指导委员会指导、全国管理决策模拟大赛组委会主办，是国内管理学科最具影响力的大学生学科竞赛之一。大赛采用商道仿真系统，模拟企业多期经营决策全过程，全面考察参赛学生的战略规划、市场营销、生产运营、财务管理等综合能力。</p><p>经济与管理学院参赛队员在指导教师杨帆老师的带领下，经过近三个月的刻苦训练，在经营分析、战略制定和团队协作等方面表现出色。学院负责人表示，管理决策模拟大赛是培养学生综合管理能力的有效平台，学院将继续加大竞赛支持力度，以赛促学提升人才培养质量。</p>', '2026-04-26 14:00:00', '168', '1', '62', '0', '2', 'admin', '2026-04-26 14:00:00', '', '2026-04-26 14:00:00', '0');

-- ============================================================
-- Part 2: 20 条通知公告 (notice_type='1', news_id 120-139)
-- ============================================================

INSERT INTO `edu_news` VALUES
('120', '关于2026年度教学成果奖申报工作的通知', '2026年度校级教学成果奖申报工作即日启动，请各单位组织教师按时通过教学成果管理平台在线提交申报材料。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各单位：</p><p>根据学校年度工作安排，2026年度校级教学成果奖申报工作即日启动。现将有关事项通知如下：</p><p>一、申报范围：全校在职教师及教学管理人员，申报成果应为近4年（2022年9月至2026年4月）取得的教学成果，含人才培养模式改革、专业建设、课程建设、教材建设、实践教学、创新创业教育等方面。</p><p>二、申报时间：即日起至2026年5月31日，逾期不予受理。</p><p>三、申报方式：登录教学成果管理平台（http://edu.zzuli.edu.cn/achievement），在线填写申报信息并上传相关证明材料。纸质材料一式两份同步提交至教务处教学研究科。</p><p>四、奖项设置：设特等奖、一等奖、二等奖三个等级，获奖成果将择优推荐申报省级教学成果奖。</p><p>五、注意事项：已获得校级及以上教学成果奖的项目，如无新的重大突破，原则上不再重复申报。</p><p>联系人：张老师，电话：0371-8660XXXX</p>', '2026-04-15 08:00:00', '392', '1', '100', '0', '1', 'admin', '2026-04-15 08:00:00', '', '2026-04-15 08:00:00', '0'),

('121', '关于提交省级教学成果奖申报材料的紧急通知', '请各学院于4月28日下班前将2026年度省级教学成果奖申报材料报送至教务处教学研究科，逾期不予受理。', '', '<p>各学院：</p><p>根据河南省教育厅《关于开展2026年度河南省高等教育省级教学成果奖评选工作的通知》（教高〔2026〕88号）要求，学校现已启动省级教学成果奖申报推荐工作。有关事项紧急通知如下：</p><p>一、申报范围：已获得2024-2025学年校级教学成果一等奖及以上的成果，每个学院限推荐1-2项。</p><p>二、申报材料：（1）《河南省高等教育省级教学成果奖申报书》（一式三份）；（2）成果总结报告（不超过5000字）；（3）支撑材料合订本（含成果应用效果证明、公开发表的教学研究论文、教材封面及版权页等）。</p><p>三、时间节点：请各学院于4月28日（周二）17:00前将申报材料电子版发送至jxk@zzuli.edu.cn，纸质版报送至教务处教学研究科（办公楼302室）。逾期不予受理，请务必按时提交。</p><p>联系人：张老师，电话：0371-8660XXXX</p>', '2026-04-25 15:00:00', '478', '1', '100', '0', '1', 'admin', '2026-04-25 15:00:00', '', '2026-04-25 15:00:00', '0'),

('122', '关于调整教学成果校级审核评分细则的通知', '为进一步规范教学成果审核流程，提高评审科学性和公正性，教务处对校级审核评分标准进行了优化调整。', '', '<p>各学院及校级审核员：</p><p>为进一步提升教学成果审核工作的规范性、科学性和公正性，教务处在广泛征求各学院和专家意见的基础上，对校级审核评分细则进行了以下优化调整：</p><p>一、调整创新性指标权重。将创新性权重由原15%提升至25%，鼓励教师在教学理念、教学模式、教学方法、教学评价等方面进行原创性探索和实践。</p><p>二、新增推广应用效果维度。增设"推广应用效果"评估维度（权重15%），重点考察成果在校内外推广应用的覆盖范围、受益面和实际应用效果，需提供相关证明材料。</p><p>三、细化教学改革类评价指标。针对教学改革类成果，增设"理论支撑"、"方案设计"、"实施过程"、"效果评价"四项二级指标，每项权重各为25%。</p><p>四、新评分细则自2026年5月1日起施行，届时教学成果管理平台将同步更新评分模板。4月30日前提交的成果仍按原标准评审。</p><p>请各审核员认真学习新细则，确保审核工作平稳过渡。</p>', '2026-04-14 10:00:00', '325', '1', '99', '0', '1', 'admin', '2026-04-14 10:00:00', '', '2026-04-14 10:00:00', '0'),

('123', '关于举办教师教学能力提升培训班的通知', '教务处拟于5月举办2026年度教师教学能力提升系列培训，邀请校内外教学名师开展专题讲座和工作坊，欢迎广大教师报名参加。', '', '<p>各学院、各位教师：</p><p>为持续提升我校教师教学能力和专业素养，推动信息技术与教育教学深度融合，教务处拟于2026年5月举办"教学创新与信息化教学能力提升"系列培训活动。具体安排如下：</p><p>一、培训时间：2026年5月6日至5月27日，每周三、周五下午14:30-17:00，共7场。</p><p>二、培训地点：科学校区教师发展中心智慧教室（教学楼A301）。</p><p>三、培训内容：（1）教学创新大赛经验分享与备赛指导；（2）混合式教学设计工作坊（线上+线下）；（3）AI辅助教学工具实操培训；（4）一流课程申报与建设指南；（5）课程思政教学设计案例分享；（6）教学学术研究与论文写作；（7）教学成果奖申报材料撰写技巧。</p><p>四、培训对象：全校在职教师均可报名参加，鼓励中青年教师和在研教改项目负责人积极参加。</p><p>五、报名方式：请于4月30日前登录教师发展中心系统在线报名，每场限额60人，先报先得。</p>', '2026-04-24 09:00:00', '206', '1', '98', '0', '1', 'admin', '2026-04-24 09:00:00', '', '2026-04-24 09:00:00', '0'),

('124', '2026届毕业设计（论文）中期检查工作安排', '教务处将于5月上旬对2026届本科毕业设计（论文）工作进行中期检查，重点检查指导教师履职情况和学生研究进展。', '', '<p>各学院：</p><p>为加强本科毕业设计（论文）过程管理，切实保障毕业设计工作质量，根据《郑州轻工业大学本科毕业设计（论文）管理办法》（校教〔2024〕15号）相关规定，决定对2026届本科毕业设计（论文）进行中期检查。具体安排如下：</p><p>一、检查时间：2026年5月6日至5月15日。</p><p>二、检查内容：（1）指导教师履职情况，包括指导记录、指导频次、指导内容等；（2）学生毕业设计（论文）工作进展，是否按任务书计划推进；（3）开题报告完成质量，包括文献综述和研究方案；（4）外文翻译完成情况；（5）实验数据或调研材料的完整性和真实性。</p><p>三、检查方式：各学院成立中期检查小组，采取学生PPT汇报、查阅过程材料、指导教师座谈交流等方式开展全面检查。学校教务处将组织专家组进行随机抽查。</p><p>四、材料报送：各学院于5月18日（周一）前将《毕业设计（论文）中期检查总结报告》电子版和纸质版报送至教务处实践教学科（办公楼308室）。</p><p>五、问题处理：对检查中发现的进展严重滞后问题，学院应及时约谈指导教师和学生，制定整改方案并报教务处备案。</p>', '2026-04-26 10:00:00', '274', '1', '97', '0', '1', 'admin', '2026-04-26 10:00:00', '', '2026-04-26 10:00:00', '0'),

('125', '关于开展2026年度教学改革研究项目立项申报的通知', '学校启动2026年度校级教学改革研究项目立项申报工作，设重点项目和一般项目两类，资助经费3万元和1万元。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各单位：</p><p>为深入贯彻落实全国教育大会精神，深化教育教学改革，鼓励广大教师积极开展教学研究，学校决定开展2026年度校级教学改革研究项目立项申报工作。有关事项通知如下：</p><p>一、项目类别与资助额度：设重点项目（资助3万元/项，立项不超过15项）和一般项目（资助1万元/项，立项不超过30项）。研究周期一般为2年。</p><p>二、申报方向：（1）课程思政建设与实施研究；（2）一流课程与一流专业建设研究；（3）实践教学体系改革与实验室建设；（4）创新创业教育与专业教育融合；（5）教学质量保障与评价体系研究；（6）教育数字化转型与智慧教学；（7）产教融合协同育人机制研究。</p><p>三、申报条件：项目负责人须具有中级及以上专业技术职称，原则上在研校级教改项目不超过1项。鼓励跨学科、跨学院联合申报。</p><p>四、申报截止时间：2026年5月20日。请将申报书电子版发送至jxk@zzuli.edu.cn，纸质版一式三份交至教务处教学研究科。</p>', '2026-04-08 09:00:00', '288', '1', '97', '0', '1', 'admin', '2026-04-08 09:00:00', '', '2026-04-08 09:00:00', '0'),

('126', '关于公布2026年春季学期教学督导工作安排的通知', '学校教学督导委员会发布本学期教学督导工作计划，将开展常规听课评课、专项检查和教学沙龙等系列活动。', '', '<p>各教学单位：</p><p>为加强教学质量监控与保障，促进教师教学能力持续提升，学校教学督导委员会制定了2025-2026学年第二学期教学督导工作计划。现将有关安排公布如下：</p><p>一、常规听课评课：校级督导专家本学期计划听课评课不少于60节次，重点覆盖各学院青年教师、新入职教师和新开设课程，听课安排将提前一天通知相关教师。</p><p>二、专项检查：本学期重点开展"混合式教学实施情况"和"课程思政建设情况"两项专项检查。混合式教学检查将抽查各学院线上线下混合课程的教学设计、资源建设和实施效果；课程思政检查将重点评估课程思政元素的融入方式和育人成效。</p><p>三、教学沙龙：计划每月举办1次教学沙龙活动，邀请优秀教师和教学竞赛获奖者分享教学经验与创新实践，营造浓厚的教学研讨氛围。</p><p>四、反馈机制：督导专家的听课评课意见将通过教务管理系统及时反馈给授课教师本人和所在学院。教师对督导意见有异议的，可在5个工作日内向教学督导委员会提出复核申请。</p>', '2026-03-25 14:00:00', '156', '1', '96', '0', '1', 'admin', '2026-03-25 14:00:00', '', '2026-03-25 14:00:00', '0'),

('127', '关于推荐优秀教学成果参加全国展示的通知', '教育部将于6月举办2026年全国高校教学成果展，现面向全校征集优秀教学成果参展项目，请各单位积极推荐。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各单位：</p><p>根据教育部高等教育司《关于举办2026年度全国高校教学成果展的通知》（教高司函〔2026〕16号），2026年度全国高校教学成果展定于6月16日至18日在北京国家会议中心举办。为充分展示我校近年来教育教学改革取得的丰硕成果，现面向全校征集参展项目。具体要求如下：</p><p>一、征集范围：（1）近三年（2023-2026年）获得校级及以上教学成果奖的项目；（2）在人才培养模式改革、课程建设、实践教学、创新创业教育等方面取得突出成效，具有较高推广价值的教学改革成果。</p><p>二、推荐名额：原则上每个学院可推荐1-2项优秀成果，成果特别突出的学院可适当增加。</p><p>三、参展形式：实物展板（统一规格）、视频展示（时长不超过5分钟）、互动演示、宣传册等多种形式相结合。</p><p>四、时间安排：请各学院于5月10日前将推荐项目汇总表及展示材料初稿提交至教务处，学校将组织专家评审遴选出最终参展项目。</p>', '2026-04-20 14:00:00', '211', '1', '95', '0', '1', 'admin', '2026-04-20 14:00:00', '', '2026-04-20 14:00:00', '0'),

('128', '关于2026年春季学期期中教学检查的通知', '教务处将于第8至9周组织春季学期期中教学检查，请各学院按要求完成自查并报送总结报告。', '', '<p>各学院、各教学单位：</p><p>为进一步规范教学管理，全面了解本学期教学运行状况，及时发现和解决教学过程中存在的问题，根据学校教学工作安排，决定于第8至9周（4月20日至4月30日）开展2026年春季学期期中教学检查工作。现将有关事项通知如下：</p><p>一、检查内容：（1）课堂教学质量，包括教师到岗、教学进度执行、课堂组织管理、学生到课率等；（2）实践教学环节，包括实验课程开出率、实习实训组织、课程设计完成质量等；（3）教学档案管理，包括教学日历、教案、作业批改记录、成绩登记等教学文件规范性。</p><p>二、检查方式：采取学院自查与学校抽查相结合的方式进行。各学院于4月23日前完成自查工作并提交自查报告（含问题清单和整改措施），学校教学检查组将于4月26日至30日进行随机抽查，抽查比例不低于各学院课程总数的20%。</p><p>三、工作要求：各学院要高度重视本次期中教学检查工作，坚持实事求是原则，认真查找问题，制定切实可行的整改措施，确保整改到位。</p>', '2026-04-18 08:30:00', '330', '1', '96', '0', '1', 'admin', '2026-04-18 08:30:00', '', '2026-04-18 08:30:00', '0'),

('129', '关于教学成果管理平台使用培训的通知', '教务处将于4月28日和29日举办两场平台操作培训，帮助教师和审核员熟练掌握新版教学成果管理平台功能。', '', '<p>各学院、各位教师和审核员：</p><p>新版教学成果管理平台已于近期上线运行，为帮助各位教师和审核人员熟练掌握平台各项功能操作，教务处拟举办两场线上专项培训。具体安排如下：</p><p>一、第一场（教师专场）：4月28日（周二）14:30-16:00。培训内容：（1）成果申报流程操作演示；（2）附件材料上传与格式要求；（3）草稿保存与提交审核；（4）申报进度实时查询；（5）审核驳回后的修改与重新提交。</p><p>二、第二场（审核员专场）：4月29日（周三）14:30-16:00。培训内容：（1）审核任务接收与分配；（2）审核流程逐项操作；（3）评分表填写规范与常见问题；（4）审核意见撰写规范与模板使用；（5）审核数据统计与分析功能。</p><p>三、培训方式：通过腾讯会议线上进行（会议号：xxx-xxxx-xxx，密码：2026），两场培训均将全程录制，视频回放将上传至教学成果管理平台供随时回看。</p><p>四、参加人员：请各学院教学秘书、拟申报教学成果的教师及所有校级审核员务必按时参加培训，并提前登录平台熟悉基本功能。</p>', '2026-04-26 16:00:00', '128', '1', '94', '0', '1', 'admin', '2026-04-26 16:00:00', '', '2026-04-26 16:00:00', '0'),

('130', '关于公布2026年度校级一流课程立项名单的通知', '经教师申报、学院推荐、专家评审和校内公示，2026年度校级一流课程立项建设名单正式公布，共计30门课程获批立项。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各单位：</p><p>根据《郑州轻工业大学一流本科课程建设实施方案》和《关于开展2026年度校级一流课程立项建设申报工作的通知》要求，经教师个人申报、学院推荐、教务处初审、校外专家函评、校教学指导委员会会评和校内公示等环节，现将2026年度校级一流课程立项建设名单予以公布。</p><p>本年度共收到申报课程67门，最终获批立项建设30门，其中线上一流课程5门、线下一流课程12门、线上线下混合式一流课程8门、虚拟仿真实验教学一流课程3门、社会实践一流课程2门。立项课程建设周期为2年，学校将给予每门课程5-10万元的建设经费支持。</p><p>请各立项课程负责人认真制定课程建设计划，按时完成建设任务。教务处将组织中期检查和结题验收，建设成效突出的课程将优先推荐申报省级、国家级一流课程。</p><p>附件：2026年度校级一流课程立项建设名单</p>', '2026-04-06 11:00:00', '367', '1', '98', '0', '1', 'admin', '2026-04-06 11:00:00', '', '2026-04-06 11:00:00', '0'),

('131', '关于开展2026年教学质量优秀奖评选工作的通知', '学校决定开展2026年教学质量优秀奖评选工作，表彰在课堂教学、实践教学和教学改革中表现突出的教师。', '', '<p>各学院：</p><p>为充分调动广大教师投身教学工作的积极性和创造性，激励教师不断提高教学水平和育人质量，学校决定开展2026年教学质量优秀奖评选工作。有关事项通知如下：</p><p>一、评选范围：本校在岗专职教师，且2024-2025学年和2025-2026学年连续承担本科教学任务，课堂教学工作量饱满。</p><p>二、评选条件：（1）师德高尚，教书育人成效显著，深受学生好评，近两年学生评教成绩排名在本学院前30%；（2）教学基本功扎实，教学方法先进，教学效果突出；（3）积极参与教学改革和教学研究，近两年主持或参与校级及以上教改项目，或发表教学研究论文1篇以上；（4）无教学事故记录。</p><p>三、评选名额：全校评选教学质量优秀奖不超过30名，其中一等奖5名、二等奖10名、三等奖15名。各学院推荐名额按专任教师总数的5%核定。</p><p>四、申报截止时间：2026年5月15日。</p>', '2026-04-22 16:00:00', '198', '1', '93', '0', '1', 'admin', '2026-04-22 16:00:00', '', '2026-04-22 16:00:00', '0'),

('132', '关于进一步加强本科课程考试管理工作的通知', '教务处发布关于加强课程考试管理的工作要求，强化命题质量、考场纪律和试卷评阅等环节的规范管理。', '', '<p>各学院、各教学单位：</p><p>课程考试是检验教学效果、评价学生学习成果的重要手段。为进一步规范考试管理，严肃考风考纪，提高考试质量，现就加强本科课程考试管理工作提出以下要求：</p><p>一、严格命题管理。命题须以课程教学大纲为依据，覆盖课程核心知识点，合理设置试题难度和题型结构。鼓励推行教考分离，公共基础课和专业核心课原则上应由非任课教师命题或从试题库抽题组卷。</p><p>二、严明考场纪律。各学院须在考前召开监考教师培训会和考生考风考纪教育会。监考教师须认真履行职责，严格执行考场规则。对考试违纪作弊行为实行"零容忍"，一经查实按学校相关规定严肃处理。</p><p>三、规范试卷评阅。推行流水阅卷和集体阅卷制度，确保评分标准统一、赋分准确、核分无误。考试成绩须在考试结束后一周内录入教务管理系统并完成成绩分析报告。</p><p>四、加强试卷归档。所有课程考试试卷（含参考答案和评分标准）须按学校档案管理要求规范归档，保存期不少于6年。</p>', '2026-03-20 10:00:00', '243', '1', '92', '0', '1', 'admin', '2026-03-20 10:00:00', '', '2026-03-20 10:00:00', '0'),

('133', '关于做好2026年度本科专业人才培养方案修订工作的通知', '学校启动2026版本科专业人才培养方案修订工作，各学院须在6月底前完成初稿并提交校教学指导委员会审议。', '', '<p>各学院：</p><p>为适应新时代高等教育发展和区域经济社会发展对人才培养的新要求，优化人才培养体系和课程设置，学校决定启动2026版本科专业人才培养方案修订工作。现将有关事项通知如下：</p><p>一、修订原则：（1）坚持立德树人根本任务，将课程思政贯穿培养全过程；（2）遵循OBE（成果导向教育）理念，明确培养目标和毕业要求；（3）强化实践教学环节，理工类专业实践教学学分比例不低于30%；（4）推进通专融合，优化通识教育与专业教育的衔接；（5）对接行业产业发展需求，增强人才培养的适应性和前瞻性。</p><p>二、修订重点：（1）科学设定毕业要求，建立课程体系与毕业要求的矩阵映射关系；（2）增加反映学科前沿和产业新技术、新业态的课程内容；（3）整合优化课程设置，减少必修课比例，增加选修课比重；（4）强化创新创业教育，设置不低于2学分的创新创业必修课程。</p><p>三、时间安排：5月15日前，各学院成立修订工作组；6月30日前，完成培养方案初稿并提交教务处；7月下旬，校教学指导委员会集中审议。</p>', '2026-04-28 09:00:00', '185', '1', '95', '0', '1', 'admin', '2026-04-28 09:00:00', '', '2026-04-28 09:00:00', '0'),

('134', '关于公布2026年校级优秀教材评选结果的通知', '经教师申报、学院推荐、专家评审和校内公示，共评选出2026年度校级优秀教材15部，其中一等奖3部、二等奖5部、三等奖7部。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各单位：</p><p>根据《郑州轻工业大学优秀教材评选办法》和《关于开展2026年度校级优秀教材评选工作的通知》要求，经教师个人申报、学院推荐、教务处初审、校外专家评审和校内公示，2026年度校级优秀教材评选工作已全部完成。现将评选结果予以公布：</p><p>本次评选共收到申报教材28部，最终评选出校级优秀教材15部，其中一等奖3部、二等奖5部、三等奖7部。获奖教材涵盖软件工程、电气工程、外国语言文学、工商管理、数学等多个学科领域，均已在教学实践中使用两届以上，得到了师生和同行的广泛认可。</p><p>学校将对获奖教材编写团队给予表彰和奖励，一等奖配套教材建设经费5万元，二等奖3万元，三等奖1万元，用于教材的持续修订和数字化资源建设。获得一等奖的教材将优先推荐参加省级和国家级优秀教材评选。</p><p>附件：2026年校级优秀教材评选获奖名单</p>', '2026-04-03 15:00:00', '312', '1', '96', '0', '1', 'admin', '2026-04-03 15:00:00', '', '2026-04-03 15:00:00', '0'),

('135', '关于进一步加强实验室安全管理工作的通知', '教务处联合保卫处发布实验室安全管理工作通知，要求各学院开展实验室安全隐患排查整治，落实安全责任制。', '', '<p>各学院、各实验中心：</p><p>为进一步加强我校实验室安全管理工作，有效防范和遏制实验室安全事故发生，切实保障师生生命财产安全和教学科研工作正常进行，现就有关事项通知如下：</p><p>一、压实安全管理责任。各学院须严格落实"党政同责、一岗双责、齐抓共管、失职追责"的实验室安全管理责任制，明确学院分管领导、实验室主任、实验员和指导教师的安全职责，层层签订安全责任书。</p><p>二、全面排查安全隐患。各学院须于5月10日前对所属实验室进行一次拉网式安全隐患大排查，重点检查：（1）危险化学品采购、存储、使用和废弃物处置全流程管理；（2）特种设备（压力容器、起重设备等）的安全检验和维护保养；（3）用电安全、消防安全设施配备及有效性；（4）实验室安全准入制度的落实情况。</p><p>三、强化安全教育与培训。严格执行实验室安全准入制度，所有进入实验室的师生必须完成安全教育培训并考核合格。各实验室须在醒目位置张贴安全操作规程和应急处置流程图。</p><p>四、各学院于5月15日前将安全隐患排查报告和整改台账报送至教务处实验室管理科。</p>', '2026-04-28 16:00:00', '156', '1', '91', '0', '1', 'admin', '2026-04-28 16:00:00', '', '2026-04-28 16:00:00', '0'),

('136', '关于做好2026届本科毕业论文（设计）答辩工作的通知', '2026届本科毕业论文（设计）答辩工作将于5月下旬至6月上旬进行，请各学院做好答辩组织、成绩评定和材料归档工作。', '', '<p>各学院：</p><p>2026届本科毕业论文（设计）工作已进入冲刺阶段，根据学校教学工作安排，现将毕业论文（设计）答辩及后续工作有关事项通知如下：</p><p>一、答辩时间：2026年5月25日至6月10日，各学院在此时间段内自行安排具体答辩日程，并于5月18日前将答辩安排表报送教务处实践教学科备案。</p><p>二、答辩资格审查：学生须满足以下条件方可参加答辩：（1）毕业论文（设计）已按任务书要求完成，经指导教师审阅同意；（2）论文查重检测文字复制比不超过30%（理工科）或25%（文科）；（3）毕业实习等实践教学环节成绩合格。</p><p>三、答辩组织要求：每个答辩小组由3-5名具有中级及以上职称的教师组成，设组长1名、秘书1名。每名学生答辩时间不少于20分钟（含汇报10分钟、提问10分钟）。答辩成绩评定应严格按照评分标准执行，优秀比例不超过本专业学生总数的15%。</p><p>四、材料归档：6月20日前完成毕业论文（设计）最终稿提交和全套档案材料归档，教务处将组织抽查。</p>', '2026-04-27 10:00:00', '356', '1', '94', '0', '1', 'admin', '2026-04-27 10:00:00', '', '2026-04-27 10:00:00', '0'),

('137', '关于公布2025-2026学年第二学期学生评教工作安排的通知', '本学期学生网上评教工作将于5月18日至5月31日开放，请各学院组织学生按时完成评教，参评率将纳入年度考核。', '', '<p>各学院、各位同学：</p><p>学生评教是学校教学质量监控体系的重要组成部分，是促进教师改进教学方法、提升教学质量的重要手段。现将2025-2026学年第二学期学生网上评教工作安排通知如下：</p><p>一、评教时间：2026年5月18日（周一）8:00至5月31日（周日）23:59，届时教务管理系统评教模块将开放。</p><p>二、评教对象与范围：本学期所有开设课程的任课教师（含实验课、实习指导教师），学生须对所选每门课程逐一进行评价。</p><p>三、评教方式：登录教务管理系统（http://jw.zzuli.edu.cn），进入"教学评价"模块，按系统提示逐项完成评分和文字建议。评教过程为匿名方式，教师无法查看具体学生的评价信息。</p><p>四、评教指标：包括教学态度、教学内容、教学方法、教学效果和课程思政等维度，具体指标以系统显示内容为准。请同学们本着客观公正、认真负责的态度进行评价，合理表达意见建议。</p><p>五、注意事项：未完成评教的学生将无法查看本学期课程成绩和进行下学期选课，请务必按时完成。各学院学生参评率将纳入学院年度教学工作考核指标体系。</p>', '2026-04-16 08:00:00', '423', '1', '93', '0', '1', 'admin', '2026-04-16 08:00:00', '', '2026-04-16 08:00:00', '0'),

('138', '关于组织申报2026年国家级大学生创新创业训练计划项目的通知', '学校启动2026年国家级大学生创新创业训练计划项目申报工作，设创新训练、创业训练和创业实践三类项目。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院：</p><p>根据教育部高等教育司《关于做好2026年国家级大学生创新创业训练计划项目申报工作的通知》要求，学校现启动2026年国家级"大创计划"项目申报工作。有关事项通知如下：</p><p>一、项目类型：（1）创新训练项目：本科生个人或团队在导师指导下，自主完成创新性研究项目设计、研究条件准备和项目实施、研究报告撰写等工作，资助额度1-2万元/项；（2）创业训练项目：本科生团队在导师指导下，完成商业计划书编制、可行性研究、模拟企业运行等工作，资助额度1-2万元/项；（3）创业实践项目：学生团队在学校导师和企业导师共同指导下，开展创业实践活动，资助额度3-5万元/项。</p><p>二、申报条件：项目负责人须为我校全日制本科一至三年级学生，每个项目参与学生不超过5人。每位学生限主持1个项目，参与项目总数不超过2个。每个项目须配备1-2名指导教师。</p><p>三、申报流程：5月20日前，项目团队在"大学生创新创业训练计划管理系统"在线填报；5月下旬，教务处组织专家评审；6月初公布立项名单。</p>', '2026-04-11 10:00:00', '378', '1', '97', '0', '1', 'admin', '2026-04-11 10:00:00', '', '2026-04-11 10:00:00', '0'),

('139', '关于做好2026年暑假期间教学实验室安全工作的通知', '暑假将至，为做好实验室安全管理工作，防范各类安全事故发生，请各学院在假前完成安全检查和隐患排查。', '', '<p>各学院、各实验中心：</p><p>2026年暑假即将来临，为切实加强暑假期间教学实验室安全管理工作，有效防范和遏制各类实验室安全事故，保障校园安全稳定，现将有关事项通知如下：</p><p>一、假前安全检查。各学院须在7月1日前对所有教学实验室进行一次全面安全检查，重点排查水电设施、消防器材、危险化学品存储、特种设备状态等，发现问题立即整改，无法立即整改的须制定防范措施和整改计划。</p><p>二、危险源管控。暑假期间原则上暂停所有涉及危险化学品和高温高压设备的教学实验。确需开展的，须经学院审批并报教务处备案，全程须有教师现场指导。危险化学品须按规定入库封存，易燃易爆物品须妥善保管。</p><p>三、实验室封闭管理。假期不使用的实验室须切断水源、电源、气源，关好门窗，张贴封条。实验室钥匙由各学院指定专人统一保管，不得随意交给学生单独持有。</p><p>四、应急值守。各学院须安排实验室安全值班人员，保持通讯畅通，遇有突发情况第一时间妥善处置并向学校报告。值班安排表于7月1日前报送教务处和保卫处。</p>', '2026-04-20 08:30:00', '239', '1', '90', '0', '1', 'admin', '2026-04-20 08:30:00', '', '2026-04-20 08:30:00', '0');

-- ============================================================
-- Part 3: 30 项教学成果 (achievement_id 200-229)
-- 全部属于 teacher_id=100, college_id=124, create_by='teacher'
-- 状态分布: 8草稿(0) + 8审核中(2) + 10已通过(3) + 4已驳回(4)
-- ============================================================

-- === 草稿 (status='0') × 8: achievement_id 200-207 ===

INSERT INTO `edu_achievement` VALUES
('200', '基于OBE理念的软件工程课程教学改革与实践', '<p>本项目以成果导向教育（OBE）理念为指导，对软件工程专业核心课程群进行了系统性教学改革。改革围绕"定义预期学习成果—反向设计课程体系—实施多元化教学—持续改进评价"四步闭环展开。在《软件工程导论》、《软件需求分析》、《软件设计与体系结构》三门核心课程中，重新梳理了课程目标与毕业要求的映射关系，设计了12个贯穿式项目案例，覆盖从需求获取到系统部署的完整软件生命周期。</p><p>项目实施两年来，学生的系统分析与设计能力显著提升，课程设计作品在全国大学生软件创新大赛中获国家级二等奖1项、省级一等奖2项。学生普遍反映，项目驱动的教学方式使理论知识与工程实践得到了有效衔接，学习目标更加清晰明确。</p>', '', '100', '124', '0', 'teacher', '2026-04-05 14:00:00', '', NULL, '0', '4', '2'),

('201', '新工科背景下计算机专业人才培养模式探索', '<p>面向新工科建设需求，本项目探索了"厚基础、宽口径、强实践、求创新"的计算机专业人才培养新模式。核心举措包括：重构课程体系，增设"人工智能导论"、"大数据技术基础"、"云计算与边缘计算"等前沿技术课程模块；建立"基础实验—综合实训—企业实习"三层次实践教学体系；引入企业认证课程，实现课证融通；搭建校企协同育人平台，与华为、中软国际等企业深度合作。</p><p>经过两年的教学实践，专业毕业生一次就业率从86%提升至94%，用人单位满意度达到96.5%。2025年计算机科学与技术专业成功通过教育部工程教育认证，标志着专业建设迈上了新台阶。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '0', 'teacher', '2026-04-03 09:00:00', '', NULL, '0', '4', '1'),

('202', '大学英语课程思政教学设计与实施路径研究', '<p>本项目将课程思政理念有机融入大学英语课程教学全过程，构建了"语言学习+文化理解+价值引领"三位一体的教学模式。在教学中精选反映当代中国发展成就、中国优秀传统文化和社会主义核心价值观的英语素材，引导学生在提升语言技能的同时增进文化自信和家国情怀。</p><p>项目团队开发了包含20个教学单元的课程思政教学资源库，涵盖科技创新、乡村振兴、生态文明、一带一路等主题。课程实施后，学生的文化自信意识显著增强，课程满意度从84%提升至93%。该教学模式已在校内多个外语教学班级推广应用。</p>', '', '100', '124', '0', 'teacher', '2026-04-01 10:00:00', '', NULL, '0', '1', '3'),

('203', '虚拟仿真技术在工程训练教学中的应用研究', '<p>本项目将虚拟仿真技术引入工程训练实践教学，开发了涵盖机械加工、电子装配、工业机器人操作等模块的虚拟仿真实训平台。平台采用Unity3D引擎开发，模拟真实工程训练场景，学生可在虚拟环境中安全地进行设备操作练习，有效解决了传统工程训练中设备台套数不足、部分工种存在安全隐患等问题。</p><p>在为期一个学期的试点教学中，参与虚拟仿真训练的学生在实际设备上的操作熟练度提升30%，安全事故发生率降低至零，实训教学效率显著提高。该方案具有较高的推广价值。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '0', 'teacher', '2026-04-08 15:00:00', '', NULL, '0', '3', '4'),

('204', '基于项目驱动的Python程序设计课程改革', '<p>本项目对《Python程序设计》课程进行了以项目驱动为核心的全面改革。摒弃了传统"语法讲解—简单示例—上机练习"的教学模式，代之以"项目引入—问题分解—知识讲授—编码实践—项目完善"的五步教学法。课程设计了"数据分析与可视化"、"网络爬虫与信息提取"、"Web应用开发"、"机器学习入门"四个综合性课程项目。</p><p>改革实施后，学生的编程实践能力和解决实际问题的能力显著提升。课程期末项目作品质量较改革前提高明显，部分优秀学生作品已具备实际应用价值。但在实施过程中也发现，部分基础薄弱的学生在项目初期存在畏难情绪，需要进一步加强分层指导。</p>', '', '100', '124', '0', 'teacher', '2026-04-10 11:00:00', '', NULL, '0', '6', '3'),

('205', '校企协同培养应用型电气工程人才的实践', '<p>本项目联合国家电网河南省电力公司、许继集团等企业，构建了"3+1"应用型人才培养模式（3年校内学习+1年企业实践），探索校企深度融合的电气工程人才培养新路径。校企双方共同制定培养方案、联合开发课程资源、共建实践教学基地。学生在企业实习期间直接参与智能变电站调试、配电网规划、新能源发电项目等真实工程实践。</p><p>项目实施以来，累计已有120名学生进入合作企业完成实习实训，毕业生工程实践能力和职业素养得到用人单位高度认可，专业对口就业率从72%提升至91%。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '0', 'teacher', '2026-04-12 10:00:00', '', NULL, '0', '2', '2'),

('206', '基于过程性评价的课程考核体系改革研究', '<p>本项目改革了传统"一考定成绩"的课程考核方式，构建了涵盖全过程、多维度的课程考核评价体系。评价维度包括：课堂参与（15%）、线上学习数据（15%）、阶段测验（20%）、课程项目（25%）、期末综合考核（25%）。利用学习通平台和教学成果管理平台自动采集学习行为数据，为过程性评价提供客观数据支撑。</p><p>经过两个学期的试点实践，学生的课堂参与度和学习主动性显著提升，期末成绩分布更趋合理，高分和低分两极分化现象得到有效缓解。评审专家认为该评价体系设计科学、操作性强。</p>', '', '100', '124', '0', 'teacher', '2026-04-15 08:00:00', '', NULL, '0', '5', '4'),

('207', '专业课程与创新创业教育融合的教学模式探索', '<p>本项目探索了将创新创业教育有机融入专业课程教学的新模式。在专业课程中设置"创新思维训练"、 "创业案例分析"等教学环节，引导学生从专业知识中发现创新点和创业机会。课程增设了"商业计划书撰写"实训环节，学生以专业所学技术为基础，模拟完成从创意产生到商业计划的全过程。</p><p>项目在3个专业、6个教学班中进行了试点，学生在"互联网+"大学生创新创业大赛中获省级银奖2项、铜奖3项。学生普遍反馈该教学模式有效提升了创新意识和创业思维，但同时也建议增加企业导师参与指导的频次。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '0', 'teacher', '2026-04-18 16:00:00', '', NULL, '0', '3', '1');

-- === 审核中 (status='2') × 8: achievement_id 208-215 ===

INSERT INTO `edu_achievement` VALUES
('208', '人工智能通识课程体系建设方案研究', '<p>本项目面向全校非计算机专业学生，设计了一套"AI通识教育"课程体系建设方案。方案包括"人工智能导论"（通识必修课，32学时）、"AI与社会科学"、"AI与艺术设计"、"AI与工程技术"等方向选修课（各16学时），以及"AI创新实践工作坊"（实训环节）。课程内容强调AI基本概念、典型应用场景和伦理规范，避免深奥的数学推导，让各专业学生都能理解和应用AI技术。</p><p>课程体系建设方案已经过多轮专家论证，获得广泛认可。目前已提交校级审核，等待评审结果。如获批通过，计划于2026年秋季学期面向全校学生开设。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '2', 'teacher', '2026-04-08 09:00:00', '', NULL, '0', '1', '0'),

('209', '一流本科课程《数据结构》线上线下混合式教学改革', '<p>本项目对《数据结构》课程开展线上线下混合式教学改革。线上依托超星学习通平台建设了包含48个微课视频、200余道在线习题、10个算法可视化演示的数字化教学资源库；线下课堂采用翻转课堂模式，重点进行疑难讲解、算法设计研讨和编程实践指导。</p><p>教学资源已覆盖课程全部核心知识点，微课视频总时长超过600分钟。课程资源库已面向全校开放共享，兄弟院校也表达了引进使用的意愿。本项目已提交校级教学成果申报审核。</p>', '', '100', '124', '2', 'teacher', '2026-04-12 14:00:00', '', NULL, '0', '6', '2'),

('210', '产教融合驱动的大数据专业实践教学平台建设', '<p>本项目联合阿里云、腾讯云两家企业，共建了面向大数据专业的实践教学平台。平台集成了数据采集、数据清洗、数据存储、数据分析、数据可视化全流程工具链，提供超过20个实训项目，涵盖电商数据分析、交通流量预测、社交媒体舆情分析等真实业务场景。平台采用云原生架构部署，学生通过浏览器即可获得完整的大数据开发环境。</p><p>该平台目前已搭建完成并完成内部测试，支持Hadoop、Spark、Flink等主流大数据处理框架的实验教学。本项目已正式提交教学成果审核，等待专家评审。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '2', 'teacher', '2026-04-14 10:00:00', '', NULL, '0', '4', '1'),

('211', '\"以赛促学\"模式下大学生数学建模能力培养体系', '<p>本项目构建了以数学建模竞赛为牵引的大学生数学建模能力培养体系。建立了"通识选修课→建模培训→校内选拔→赛前集训→国赛参赛"五阶段递进培养链条，组建了由数学、计算机、经管等多学科教师组成的跨学科指导团队。每年面向全校开设《数学建模》通识选修课，覆盖学生超过300人，从中选拔优秀学生进入集训队。</p><p>该培养模式已连续运行两年，学生在各类数学建模竞赛中的获奖数量显著增长。目前该成果已正式提交审核，申报校级教学成果奖。</p>', '', '100', '124', '2', 'teacher', '2026-04-16 15:00:00', '', NULL, '0', '3', '2'),

('212', '课程思政在工科专业课程中的系统化实施路径', '<p>本项目系统探索了工科专业课程思政的实施路径，建立了"挖掘思政元素—设计融入方式—实施课堂教学—评价育人效果"四位一体的课程思政工作流程。在《电路原理》、《电子技术》、《自动控制原理》等6门专业核心课程中，系统梳理了与课程知识体系相匹配的思政元素图谱，设计了30余个课程思政教学案例。</p><p>项目团队编写了《工科专业课程思政教学指南》，包含课程思政总体设计、案例汇编和实施建议。该成果已提交校级审核，在前期的学院内部试讲中获得了良好反馈。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '2', 'teacher', '2026-04-18 09:00:00', '', NULL, '0', '1', '3'),

('213', '基于BOPPPS模型的有效课堂教学设计研究', '<p>本项目引入国际先进的BOPPPS教学模型（Bridge-in导入、Objective目标、Pre-assessment前测、Participatory Learning参与式学习、Post-assessment后测、Summary总结），对课堂教学进行了系统化重构设计。项目团队在20余门课程中推广BOPPPS模型应用，开发了配套的课堂教学设计模板和评价工具。</p><p>通过BOPPPS模型的应用，课堂教学结构更加清晰，学生课堂参与度和学习效果均有明显提升。项目组收集了丰富的课堂教学数据，撰写了多篇教学研究论文。该成果已提交教学成果审核。</p>', '', '100', '124', '2', 'teacher', '2026-04-20 11:00:00', '', NULL, '0', '5', '4'),

('214', '基于大语言模型的智能教学辅助系统设计与应用', '<p>本项目利用通用大语言模型技术，研发了面向高校教学的智能辅助系统。系统具备三大功能模块：智能出题与组卷、作业自动批改与反馈、个性化学习答疑。系统通过对接课程知识库和历年题库，能够自动生成符合教学要求的试题并智能组卷；能够对学生提交的客观题和简答题进行自动批改并提供反馈建议。</p><p>系统在4门课程的试点应用中表现良好，教师组卷效率提升约50%，作业批改工作量降低约35%。目前该成果已提交审核，申请教学成果认定。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '2', 'teacher', '2026-04-22 08:00:00', '', NULL, '0', '4', '0'),

('215', '跨学科复合型人才培养模式创新实践', '<p>本项目面向新时代对复合型人才的需求，探索了"主修专业+微专业"的跨学科人才培养模式。设计了"人工智能技术"、"数字媒体设计"、"金融科技"、"国际商务"四个微专业方向，每个微专业设置5-6门核心课程，共计15-18学分。学生可在主修专业基础上选修一个微专业，毕业时获得主修学位和微专业证书。</p><p>首批"人工智能技术"和"数字媒体设计"两个微专业已完成课程建设和师资配置，计划于2026年秋季开始招生。此人才培养方案已提交校级教学成果审核。</p>', '', '100', '124', '2', 'teacher', '2026-04-24 10:00:00', '', NULL, '0', '2', '1');

-- === 已通过 (status='3') × 10: achievement_id 216-225 ===

INSERT INTO `edu_achievement` VALUES
('216', '基于微服务架构的教学管理平台开发与应用', '<p>本项目采用Spring Cloud微服务架构，自主研发了一套面向高校的教学管理一体化平台。平台涵盖课程管理、成绩管理、教学评价、毕业设计管理和教学成果管理五大核心模块，各模块以独立微服务形式部署运行，通过API网关统一对外提供服务。</p><p>平台自2025年9月上线以来，累计服务全校18个学院、1200余名教师和20000余名学生，日活跃用户超过8000人次。平台有效解决了原有教务管理系统功能分散、数据孤岛等痛点问题，实现了教学管理数据的互通共享和业务流程的协同优化。</p><p>该成果已在3所兄弟院校推广应用，获得一致好评。项目团队围绕平台研发发表核心期刊论文2篇，获软件著作权3项。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '3', 'teacher', '2026-03-15 09:00:00', 'schoolAudit', '2026-04-10 14:00:00', '0', '4', '0'),

('217', '以学生为中心的教学质量保障体系构建与实践', '<p>本项目构建了"质量标准—过程监控—评价反馈—持续改进"四环联动的教学质量保障体系。制定了覆盖课堂教学、实践教学、毕业设计等各环节的质量标准文件32项；建立了校院两级教学督导机制和常态化教学检查制度；开发了基于大数据分析的教学质量监测平台，实现教学运行数据的实时采集和智能分析。</p><p>该体系运行两年多来，教学过程规范性显著提升，教学事故数量同比下降75%，学生评教满意度从87%提升至94%。在2025年本科教育教学审核评估中，专家组对学校的质量保障体系给予了充分肯定。</p><p>成果已在校内外广泛推广，4所兄弟院校到校学习交流，相关做法被《河南教育》杂志专题报道。</p>', '', '100', '124', '3', 'teacher', '2026-03-18 10:00:00', 'schoolAudit', '2026-04-12 09:00:00', '0', '5', '1'),

('218', '面向工程教育认证的课程目标达成度评价系统开发', '<p>本项目针对工程教育专业认证中对课程目标达成度评价的要求，自主研发了一套课程目标达成度自动计算与分析系统。系统建立了"毕业要求—课程目标—考核环节"三级映射模型，能够自动采集学生课程考核数据，计算各课程目标的达成度评价值，并生成可视化的达成度分析报告。</p><p>系统已在软件工程、计算机科学与技术、电气工程及其自动化三个专业的50余门课程中应用，覆盖学生2000余人。系统大幅提升了达成度评价的效率和准确性，评价周期从原来的2周缩短至2天，为教学持续改进提供了可靠的数据支撑。</p><p>该系统已通过校级教学成果审核，并在2025年工程教育认证现场考查中获得了认证专家的高度评价，被推荐为可推广的典型案例。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '3', 'teacher', '2026-03-20 08:00:00', 'schoolAudit', '2026-04-14 11:00:00', '0', '5', '2'),

('219', '翻转课堂在工科专业基础课中的规模化应用研究', '<p>本项目在工科专业基础课程中大规模推广翻转课堂教学模式，覆盖了《高等数学》、《大学物理》、《电路分析》、《C语言程序设计》等8门基础课程，累计涉及50余个教学班、4000余名学生。课前学生通过微课视频和在线自测完成基础知识学习，课堂时间用于问题研讨、案例分析和针对性答疑。</p><p>经过四个学期的持续实践，对比传统教学模式，翻转课堂班级的学生期末平均成绩提高了8.5分，不及格率下降了10个百分点。学生自主学习能力、课堂参与度和团队协作能力均获得显著提升。</p><p>项目团队围绕翻转课堂教学研究发表教学改革论文4篇，建设完成8门课程的线上教学资源库，形成了可推广的翻转课堂实施规范和教师培训方案。</p>', '', '100', '124', '3', 'teacher', '2026-03-22 14:00:00', 'schoolAudit', '2026-04-16 08:00:00', '0', '4', '3'),

('220', '校企共建产业学院培养应用型ICT人才的研究与实践', '<p>本项目联合华为、新华三、中软国际等ICT行业龙头企业，共建了"ICT产业学院"，探索深度产教融合的应用型ICT人才培养模式。产业学院实行理事会领导下的院长负责制，校企双方共建专业建设委员会、课程开发团队和双师型教师队伍。</p><p>在课程建设方面，引入华为HCIA/HCIP认证课程、新华三H3CNE认证课程等企业认证资源，开发了12门校企合作课程。在实践教学方面，投入500余万元建设了云计算、大数据、网络通信三大校企共建实验室，企业工程师累计进校授课超过1200学时。</p><p>产业学院已培养两届毕业生共计280人，毕业生获得行业认证证书的比例达到85%，就业对口率超过92%，平均起薪较同专业普通班级高出22%。该成果已通过校级审核认定。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '3', 'teacher', '2026-03-25 10:00:00', 'schoolAudit', '2026-04-18 15:00:00', '0', '2', '0'),

('221', '大学物理实验课程虚拟仿真教学资源建设', '<p>本项目针对大学物理实验教学中存在的实验设备昂贵、部分实验存在安全隐患、实验台套数不足等问题，利用虚拟仿真技术建设了大学物理实验教学资源库。资源库涵盖力学、热学、电磁学、光学和近代物理五大模块共40个虚拟仿真实验项目，通过3D建模和物理引擎高度还原真实实验环境和操作过程。</p><p>虚拟仿真实验资源已全面应用于全校工科专业的大学物理实验教学，与真实物理实验形成"虚实结合、相互补充"的实验教学新模式。学生在虚拟实验中可以反复操作、自由探索，实验学习效果明显提升，实验报告质量显著提高。</p><p>该项目已通过校级教学成果审核，相关成果在省级虚拟仿真实验教学项目评选中获评优秀，并在全省多所高校推广应用。学生对虚拟仿真实验的满意度达到91%。</p>', '', '100', '124', '3', 'teacher', '2026-03-28 09:00:00', 'schoolAudit', '2026-04-19 10:00:00', '0', '3', '3'),

('222', '基于学习分析技术的个性化教学干预研究', '<p>本项目利用学习分析技术（Learning Analytics），构建了学生学业预警和个性化教学干预系统。系统通过采集学生在教务系统、学习通平台和图书馆系统的多维行为数据，构建学生画像，识别学业困难学生并进行分级预警，同时为教师提供针对性的教学干预建议。</p><p>系统自2025年秋季学期投入使用后，累计识别出学业预警学生326人，通过辅导员谈话、学业帮扶、课程辅导等干预措施，其中268名学生（82.2%）的学业状况得到明显改善。系统为教师提供了课堂参与度分析、知识点掌握度分析和学习投入度分析等多维度学情报告。</p><p>该成果在数据驱动教学决策方面具有创新性，已通过校级教学成果审核。研究成果发表SSCI/SCI教学研究论文2篇。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '3', 'teacher', '2026-04-01 08:00:00', 'schoolAudit', '2026-04-21 09:00:00', '0', '1', '2'),

('223', '高校教师教学能力发展体系的构建与实施', '<p>本项目构建了"入职培训—导师带教—竞赛磨砺—研修提升—名师引领"五阶递进的高校教师教学能力发展体系。体系覆盖教师职业生涯全过程：新教师入职培训（第一年，120学时培训+微格教学训练）、青年教师导师制（1-3年，一对一指导）、教学竞赛（每年，以赛促教）、专题研修（每学期，教学学术工作坊）、教学名师培育（长期，个性化发展计划）。</p><p>自该体系实施以来，已累计培训新教师186人，结业率100%；组织校级教学竞赛6届，参与者超过500人次；培育省级教学名师2人、校级教学名师8人。教师教学能力发展中心获评省级示范教师发展中心。</p><p>该成果已通过校级教学成果审核，构建的教师发展体系具有系统性、科学性和可操作性，对同类高校教师队伍建设具有参考价值，已在省内3所高校推广借鉴。</p>', '', '100', '124', '3', 'teacher', '2026-04-02 10:00:00', 'schoolAudit', '2026-04-22 14:00:00', '0', '1', '4'),

('224', '基于SPOC的大学英语混合式教学模式创新', '<p>本项目基于SPOC（小规模限制性在线课程）理念，对大学英语课程进行了混合式教学模式创新改革。在超星学习通平台建设了包含120个微课视频、500余道自适应练习、AI口语陪练模块和智能写作批改功能的SPOC课程平台。线下课堂采用"以输出为导向"的任务型教学模式，重点开展口语交流、写作研讨和跨文化交际训练。</p><p>该模式实施三个学期以来，覆盖学生3600余人。学生的大学英语四级通过率从72%提升至89%，六级通过率从28%提升至42%。学生英语综合应用能力特别是口语表达能力得到显著提升。</p><p>该成果已通过校级审核认定，SPOC课程平台面向省内高校开放共享，累计有8所高校的12000余名学生使用。获评省级线上线下混合式一流课程。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '3', 'teacher', '2026-04-05 09:00:00', 'schoolAudit', '2026-04-24 10:00:00', '0', '6', '1'),

('225', '实践教学安全管理体系构建与运行机制研究', '<p>本项目针对高校实践教学环节安全管理的薄弱环节，构建了"制度规范—教育培训—过程监控—应急响应—事故追责"五位一体的实践教学安全管理体系。制定了覆盖实验室、实训中心、校外实习基地等场所的安全管理制度文件45项；建立了实验室安全准入考试制度，通过率须达到100%方可进入实验室；开发了实验室安全巡检信息系统，实现安全隐患排查整改的闭环管理。</p><p>安全管理体系运行两年多来，学校实践教学安全形势持续稳定向好，实验室安全隐患整改率达到98%，师生安全意识和应急处置能力显著增强，实现了实践教学安全零事故的目标。</p><p>该成果已通过校级教学成果审核，形成的安全管理体系文件和实践经验具有较好的推广应用价值，已在全省多所高校交流推广。</p>', '', '100', '124', '3', 'teacher', '2026-04-08 15:00:00', 'schoolAudit', '2026-04-26 08:00:00', '0', '5', '2');

-- === 已驳回 (status='4') × 4: achievement_id 226-229 ===

INSERT INTO `edu_achievement` VALUES
('226', '基于知识图谱的自适应学习系统开发与应用', '<p>本项目利用知识图谱技术，构建了面向《高等数学》课程的自适应学习系统。系统将课程知识点及其前置关系建模为知识图谱，根据学生的测试表现自动诊断知识薄弱点，并个性化推荐学习路径和学习资源。系统包含知识点图谱（覆盖356个知识节点）、智能诊断引擎和资源推荐引擎三大模块。</p><p>系统在3个教学班试点应用，试点班级期末平均成绩较对照班级高出5.2分。但评审专家指出，该系统的自适应算法复杂度偏低，知识图谱的构建粒度不够精细，且目前仅覆盖一门课程，推广应用的可扩展性问题尚未解决。建议进一步完善技术方案，扩大试点范围后再重新申报。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '4', 'teacher', '2026-03-18 08:00:00', 'schoolAudit', '2026-04-15 16:00:00', '0', '4', '3'),

('227', '大规模在线开放课程（MOOC）教学质量保障机制研究', '<p>本项目研究探索了大规模在线开放课程（MOOC）的教学质量保障机制，提出了涵盖"课程设计审核—教学过程监控—学习效果评价—质量持续改进"四个环节的MOOC质量保障框架。项目组对国内外主流MOOC平台上的120门课程进行了质量评价实证研究，分析了影响MOOC教学质量的关键因素。</p><p>评审专家认为，该研究具有较强的理论价值，但在本校实践应用方面不够充分。项目主要进行的是文献研究和案例调查，缺少真实的MOOC建设和运营实践经验。建议在实际建设并运行至少一门MOOC课程之后，结合实践经验完善质量保障体系，再重新提交申请。</p>', '', '100', '124', '4', 'teacher', '2026-04-06 10:00:00', 'schoolAudit', '2026-04-22 11:00:00', '0', '5', '4'),

('228', '智慧教室环境下的互动教学模式研究', '<p>本项目利用学校新建的40间智慧教室，探索了基于智慧教室环境的互动教学模式。设计了"多屏互动教学"、"即时反馈测验"、"分组协作学习"、"远程互动课堂"四种智慧教室教学模式，并开发了配套的教学活动设计方案和教师操作手册。</p><p>经评审，该成果存在以下主要问题：一是教学模式的创新性不足，所提出的四种模式在同类研究中已有较多报道，缺乏原创性的教学理论贡献；二是教学效果的实证数据不够充分，仅通过问卷调查获取了学生的满意度数据，缺少客观的学业成绩对比分析和长期跟踪数据。建议进一步深化研究设计，积累更多实证数据后重新申报。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '100', '124', '4', 'teacher', '2026-04-10 14:00:00', 'schoolAudit', '2026-04-25 09:00:00', '0', '4', '2'),

('229', '大学生学业指导与生涯规划教育体系建设', '<p>本项目构建了"课程教育—团体辅导—个体咨询—跟踪服务"四级联动的学生学业指导与生涯规划教育体系。开设了《大学生学业规划与职业发展》通识必修课（16学时），建立了学业指导中心，配备了专职学业导师，引入了个性化测评工具系统。</p><p>评审专家指出，该体系的设计理念较为全面，但实施时间较短，仅运行了一个学期，体系建设成效尚不明显，缺乏足够的数据支撑来证明其对提升学生学业成就和就业竞争力的显著作用。建议至少运行一个完整学年，积累充分的效果评价数据后重新提交审核。</p>', '', '100', '124', '4', 'teacher', '2026-04-14 09:00:00', 'schoolAudit', '2026-04-28 15:00:00', '0', '2', '1');

