INSERT INTO `edu_audit_record` VALUES
('300', '216', '2', '1', '成果创新性强，自主研发的教学管理平台架构设计合理，实际应用效果显著，已在多所高校推广应用，具有较高的推广价值。实践效果数据翔实，同意通过审核。', '103', 'schoolAudit', '2026-04-10 14:00:00'),
('301', '217', '2', '1', '教学质量保障体系设计系统完整，覆盖了教学全过程，运行两年多取得了显著成效，相关做法已被校内外广泛借鉴。材料规范、数据充分，同意通过。', '103', 'schoolAudit', '2026-04-12 09:00:00'),
('302', '218', '2', '1', '课程目标达成度评价系统设计科学合理，解决了认证工作中的实际痛点，应用覆盖范围广，效率提升效果显著。在工程教育认证中发挥了重要作用，同意通过审核。', '103', 'schoolAudit', '2026-04-14 11:00:00'),
('303', '219', '2', '1', '翻转课堂教学模式推广力度大，覆盖8门课程50余个教学班，实践数据翔实可靠。学生的学习效果和自主学习能力均有明显提升。值得推广，同意通过审核。', '103', 'schoolAudit', '2026-04-16 08:00:00'),
('304', '220', '2', '1', '校企共建产业学院是产教融合的积极探索，合作企业层次高、合作内容深入、培养成效突出。毕业生就业数据表现抢眼，成果具有示范引领作用，同意通过。', '103', 'schoolAudit', '2026-04-18 15:00:00'),
('305', '221', '2', '1', '虚拟仿真实验教学资源建设质量高、覆盖面广，"虚实结合"的实验教学模式有效解决了传统实验教学中的痛点问题。学生满意度高，推广效果好，同意通过审核。', '103', 'schoolAudit', '2026-04-19 10:00:00'),
('306', '222', '2', '1', '基于学习分析技术的个性化教学干预具有创新性，系统设计科学、数据驱动特征明显，学业预警和干预成效显著。研究有深度，发表高水平论文，同意通过。', '103', 'schoolAudit', '2026-04-21 09:00:00'),
('307', '223', '2', '1', '教师教学能力发展体系层次分明、内容充实、覆盖教师职业生涯全周期，体系运行效果好，培育了一批优秀教学人才。具有较高推广参考价值，同意通过审核。', '103', 'schoolAudit', '2026-04-22 14:00:00'),
('308', '224', '2', '1', 'SPOC混合式大学英语教学模式创新性强，线上资源丰富、线下教学设计合理。学生四级通过率提升效果显著，平台共享面广，获评省级一流课程，同意通过。', '103', 'schoolAudit', '2026-04-24 10:00:00'),
('309', '225', '2', '1', '实践教学安全管理体系建设具有很强的现实意义，制度体系完善、运行机制有效，实现了安全零事故目标，对全省高校都具参考价值。材料充分，同意通过。', '103', 'schoolAudit', '2026-04-26 08:00:00'),
('310', '226', '2', '2', '自适应学习系统的技术方案尚不够成熟，知识图谱构建粒度偏粗，自适应算法有待优化。建议完善技术方案，扩大试点覆盖范围，积累更多实证数据后重新申报。', '103', 'schoolAudit', '2026-04-15 16:00:00'),
('311', '227', '2', '2', 'MOOC教学质量保障机制的理论研究有一定深度，但本校MOOC建设和运营实践不足，缺少一手实践经验支撑。建议实际建设运行至少一门MOOC课程后，结合实践经验重新提交。', '103', 'schoolAudit', '2026-04-22 11:00:00'),
('312', '228', '2', '2', '智慧教室互动教学模式缺乏原创性理论贡献，所提出的模式在同类文献中已多有报道。教学效果的实证数据不够充分，建议增加客观量化评价指标，深化研究设计后重新申报。', '103', 'schoolAudit', '2026-04-25 09:00:00'),
('313', '229', '2', '2', '学业指导与生涯规划教育体系建设设计理念合理，但实施时间较短（仅一个学期），成效数据不充分。建议至少运行一个完整学年，收集足够的效果评价数据后重新提交审核。', '103', 'schoolAudit', '2026-04-28 15:00:00');

